  "content": "export interface Session {
  session_key: string;
  title: string;
  date: string;
  source: string;
  path: string;
  user: string;
  folder: string;
}

export interface StatsData {
  dates: string[];
  projects: string[];
  series: Record<string, number[]>;
}

const BASE = "";

export async function fetchSessions(): Promise<Session[]> {
  const res = await fetch(`${BASE}/api/sessions`);
  if (!res.ok) throw new Error(`Failed to fetch sessions: ${res.status}`);
  return res.json();
}

export async function fetchSessionContent(key: string): Promise<string> {
  const res = await fetch(
    `${BASE}/api/sessions/${encodeURIComponent(key)}/content`
  );
  if (!res.ok) throw new Error(`Failed to fetch content: ${res.status}`);
  return res.text();
}

export async function searchSessions(q: string): Promise<Session[]> {
  if (!q.trim()) return [];
  const res = await fetch(
    `${BASE}/api/search?q=${encodeURIComponent(q)}`
  );
  if (!res.ok) throw new Error(`Search failed: ${res.status}`);
  return res.json();
}

export async function fetchStats(): Promise<StatsData> {
  const res = await fetch(`${BASE}/api/stats`);
  if (!res.ok) throw new Error(`Failed to fetch stats: ${res.status}`);
  return res.json();
}
"
}

