  "content": "import { useState, useEffect, useCallback } from "react";
import { Session, fetchSessions, searchSessions } from "@/lib/api";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Search } from "lucide-react";
import { cn } from "@/lib/utils";

interface SessionListProps {
  onSelect: (session: Session) => void;
  selected: Session | null;
}

const SOURCE_COLORS: Record<string, string> = {
  claude: "bg-orange-100 text-orange-800",
  codex: "bg-green-100 text-green-800",
  cursor: "bg-blue-100 text-blue-800",
};

function formatDate(iso: string): string {
  if (!iso) return "";
  try {
    return new Date(iso).toLocaleDateString(undefined, {
      year: "numeric",
      month: "short",
      day: "numeric",
    });
  } catch {
    return iso.slice(0, 10);
  }
}

function humanTitle(session: Session): string {
  const title = session.title || "";
  return title
    .replace(/^\d{4}-\d{2}-\d{2}-\d{4}-/, "")
    .replace(/-/g, " ")
    .trim();
}

export function SessionList({ onSelect, selected }: SessionListProps) {
  const [allSessions, setAllSessions] = useState<Session[]>([]);
  const [displayed, setDisplayed] = useState<Session[]>([]);
  const [query, setQuery] = useState("");
  const [loading, setLoading] = useState(true);
  const [searching, setSearching] = useState(false);

  useEffect(() => {
    fetchSessions()
      .then((data) => {
        setAllSessions(data);
        setDisplayed(data);
      })
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  const handleSearch = useCallback(
    async (q: string) => {
      setQuery(q);
      if (!q.trim()) {
        setDisplayed(allSessions);
        return;
      }
      // Client-side fuzzy filter first
