  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from "recharts";
import { StatsData } from "@/lib/api";

const CHART_COLORS = [
  "#2563eb", "#16a34a", "#dc2626", "#d97706", "#7c3aed",
  "#0891b2", "#be185d", "#65a30d", "#ea580c", "#6366f1",
];

interface StackedChartProps {
  data: StatsData;
  topN?: number;
}

export function StackedChart({ data, topN = 10 }: StackedChartProps) {
  if (!data.dates.length) {
    return <div className="text-muted-foreground text-sm p-4">No data.</div>;
  }

  // Pick top-N projects by total words
  const projectTotals = data.projects.map((p) => ({
    name: p,
    total: data.series[p]?.reduce((a, b) => a + b, 0) ?? 0,
  }));
  projectTotals.sort((a, b) => b.total - a.total);
  const top = projectTotals.slice(0, topN).map((p) => p.name);

  // Build chart data — bucket by week if > 60 days
  const bucketSize = data.dates.length > 60 ? 7 : 1;
  const buckets: Array<Record<string, number | string>> = [];
  for (let i = 0; i < data.dates.length; i += bucketSize) {
    const label = data.dates[i];
    const entry: Record<string, number | string> = { date: label };
    for (const project of top) {
      let sum = 0;
      for (let j = i; j < Math.min(i + bucketSize, data.dates.length); j++) {
        sum += data.series[project]?.[j] ?? 0;
      }
      entry[project] = sum;
    }
    buckets.push(entry);
  }

  return (
    <ResponsiveContainer width="100%" height={300}>
      <AreaChart data={buckets} margin={{ top: 10, right: 20, left: 0, bottom: 0 }}>
        <CartesianGrid strokeDasharray="3 3" className="stroke-border" />
        <XAxis
          dataKey="date"
          tick={{ fontSize: 11 }}
          tickFormatter={(v: string) => v.slice(5)}
        />
        <YAxis tick={{ fontSize: 11 }} />
        <Tooltip />
        <Legend />
        {top.map((project, idx) => (
          <Area
            key={project}
            type="monotone"
            dataKey={project}
            stackId="1"
            stroke={CHART_COLORS[idx % CHART_COLORS.length]}
            fill={CHART_COLORS[idx % CHART_COLORS.length]}
            fillOpacity={0.6}
          />
        ))}
      </AreaChart>
    </ResponsiveContainer>
  );
}
"
}

