];

interface ExpandedChartProps {
  data: StatsData;
  topN?: number;
}

export function ExpandedChart({ data, topN = 10 }: ExpandedChartProps) {
  if (!data.dates.length) {
    return <div className="text-muted-foreground text-sm p-4">No data.</div>;
  }

  // Pick top-N projects by total words
  const projectTotals = data.projects.map((p) => ({
    name: p,
    total: data.series[p]?.reduce((a, b) => a + b, 0) ?? 0,
  }));
  projectTotals.sort((a, b) => b.total - a.total);
  const top = projectTotals.slice(0, topN).map((p) => p.name);

  const bucketSize = data.dates.length > 60 ? 7 : 1;
  const buckets: Array<Record<string, number | string>> = [];
  for (let i = 0; i < data.dates.length; i += bucketSize) {
    const label = data.dates[i];
    const entry: Record<string, number | string> = { date: label };
    let rowTotal = 0;
    const raw: Record<string, number> = {};
    for (const project of top) {
