   118→          s.source.toLowerCase().includes(lower) ||
   119→          s.folder.toLowerCase().includes(lower) ||
   120→          sessionProject(s).toLowerCase().includes(lower)
   121→      );
   122→      setDisplayed(fuzzy);
   123→    },
