   134→      try {
   135→        const results = await searchSessions(query);
   136→        if (results.length > 0) {
   137→          const filtered = results.filter((s) => {
   138→            if (sources.size > 0 && !sources.has(s.source)) return false;
   139→            const proj = sessionProject(s);
