1→import {
     2→  AreaChart,
     3→  Area,
     4→  XAxis,
     5→  YAxis,
     6→  CartesianGrid,
     7→  Tooltip,
     8→  Legend,
     9→  ResponsiveContainer,
    10→} from "recharts";
    11→import { StatsData } from "@/lib/api";
    12→
    13→const CHART_COLORS = [
    14→  "#2563eb", "#16a34a", "#dc2626", "#d97706", "#7c3aed",
    15→  "#0891b2", "#be185d", "#65a30d", "#ea580c", "#6366f1",
    16→];
    17→
    18→interface StackedSourceChartProps {
    19→  data: StatsData;
    20→}
    21→
    22→export function StackedSourceChart({ data }: StackedSourceChartProps) {
    23→  const bySource = data?.by_source;
    24→  if (!bySource?.dates?.length) {
    25→    return <div className="text-muted-foreground text-sm p-4">No data.</div>;
    26→  }
    27→
    28→  const sources = bySource.projects;
    29→  const bucketSize = bySource.dates.length > 60 ? 7 : 1;
    30→  const buckets: Array<Record<string, number | string>> = [];
    31→  for (let i = 0; i < bySource.dates.length; i += bucketSize) {
    32→    const entry: Record<string, number | string> = { date: bySource.dates[i] };
    33→    for (const source of sources) {
    34→      let sum = 0;
    35→      for (let j = i; j < Math.min(i + bucketSize, bySource.dates.length); j++) {
    36→        sum += bySource.series[source]?.[j] ?? 0;
    37→      }
    38→      entry[source] = sum;
    39→    }
    40→    buckets.push(entry);
    41→  }
    42→
    43→  return (
