    25→
    26→const SOURCES = ["claude", "cursor", "codex"] as const;
    27→
    28→const SOURCE_ICONS: Record<string, React.ReactNode> = {
    29→  claude: <Sparkles className="size-4 text-orange-600" />,
    30→  codex: <Terminal className="size-4 text-green-600" />,
    31→  cursor: <MousePointerClick className="size-4 text-blue-600" />,
    32→};
    33→
    34→interface SessionFiltersProps {
    35→  sessions: Session[];
    36→  sources: Set<string>;
    37→  projects: Set<string>;
    38→  onSourcesChange: (sources: Set<string>) => void;
    39→  onProjectsChange: (projects: Set<string>) => void;
    40→}
    41→
    42→export function SessionFilters({
    43→  sessions,
    44→  sources,
    45→  projects,
    46→  onSourcesChange,
    47→  onProjectsChange,
    48→}: SessionFiltersProps) {
    49→  const [projectSearch, setProjectSearch] = useState("");
    50→
    51→  const allProjects = useMemo(() => {
    52→    const set = new Set<string>();
    53→    for (const s of sessions) {
    54→      const p = s.project || s.folder?.split("/").pop() || "";
    55→      if (p) set.add(p);
    56→    }
    57→    return Array.from(set).sort();
    58→  }, [sessions]);
    59→
    60→  const filteredProjects = useMemo(() => {
    61→    if (!projectSearch.trim()) return allProjects;
    62→    const q = projectSearch.toLowerCase();
    63→    return allProjects.filter((p) => p.toLowerCase().includes(q));
    64→  }, [allProjects, projectSearch]);
    65→
    66→  const toggleSource = (source: string) => {
    67→    const next = new Set(sources);
    68→    if (next.has(source)) next.delete(source);
    69→    else next.add(source);
    70→    onSourcesChange(next);
    71→  };
    72→
    73→  const toggleProject = (project: string) => {
    74→    const next = new Set(projects);
    75→    if (next.has(project)) next.delete(project);
    76→    else next.add(project);
    77→    onProjectsChange(next);
    78→  };
    79→
    80→  const activeCount = sources.size + projects.size;
    81→
    82→  return (
    83→    <DropdownMenu>
    84→      <DropdownMenuTrigger asChild>
    85→        <Button
    86→          variant="outline"
    87→          size="icon"
    88→          className="h-8 w-8 shrink-0 relative"
    89→          title="Filters"
    90→        >
    91→          <ListFilter className="h-4 w-4" />
    92→          {activeCount > 0 && (
    93→            <Badge className="absolute -top-1 -right-1 h-4 min-w-4 p-0 justify-center text-[10px]">
    94→              {activeCount}
    95→            </Badge>
    96→          )}
    97→        </Button>
    98→      </DropdownMenuTrigger>
    99→      <DropdownMenuContent align="end" className="w-56">
   100→        {/* Tools submenu */}
   101→        <DropdownMenuSub>
   102→          <DropdownMenuSubTrigger>
   103→            Tools
   104→            {sources.size > 0 && (
   105→              <Badge variant="secondary" className="ml-auto h-5 min-w-5 justify-center px-1 text-[10px]">
   106→                {sources.size}
   107→              </Badge>
   108→            )}
   109→          </DropdownMenuSubTrigger>
   110→          <DropdownMenuSubContent className="w-44">
   111→            <DropdownMenuLabel className="text-xs text-muted-foreground font-normal">
   112→              Show sessions from
   113→            </DropdownMenuLabel>
   114→            {SOURCES.map((source) => (
   115→              <DropdownMenuCheckboxItem
   116→                key={source}
   117→                checked={sources.has(source)}
   118→                onCheckedChange={() => toggleSource(source)}
   119→              >
   120→                <span className="flex items-center gap-2">
   121→                  {SOURCE_ICONS[source]}
   122→                  <span className="capitalize">{source}</span>
   123→                </span>
   124→              </DropdownMenuCheckboxItem>
   125→            ))}
   126→          </DropdownMenuSubContent>
   127→        </DropdownMenuSub>
   128→
   129→        <DropdownMenuSeparator />
   130→
   131→        {/* Projects submenu */}
   132→        <DropdownMenuSub>
   133→          <DropdownMenuSubTrigger>
   134→            Projects
   135→            {projects.size > 0 && (
   136→              <Badge variant="secondary" className="ml-auto h-5 min-w-5 justify-center px-1 text-[10px]">
   137→                {projects.size}
   138→              </Badge>
   139→            )}
   140→          </DropdownMenuSubTrigger>
   141→          <DropdownMenuSubContent className="w-52 p-0">
   142→            <div className="p-2">
   143→              <Input
   144→                placeholder="Search projects…"
   145→                value={projectSearch}
   146→                onChange={(e) => setProjectSearch(e.target.value)}
   147→                className="h-7 text-xs"
   148→                onClick={(e) => e.stopPropagation()}
   149→                onKeyDown={(e) => e.stopPropagation()}
   150→              />
   151→            </div>
   152→            <DropdownMenuSeparator className="my-0" />
   153→            <div className="max-h-48 overflow-y-auto p-1">
   154→              {filteredProjects.length === 0 ? (
   155→                <p className="px-2 py-3 text-center text-xs text-muted-foreground">
   156→                  No projects
   157→                </p>
   158→              ) : (
   159→                filteredProjects.map((project) => (
   160→                  <DropdownMenuCheckboxItem
   161→                    key={project}
   162→                    checked={projects.has(project)}
   163→                    onCheckedChange={() => toggleProject(project)}
   164→                  >
   165→                    <span className="truncate">{project}</span>
   166→                  </DropdownMenuCheckboxItem>
   167→                ))
   168→              )}
   169→            </div>
   170→          </DropdownMenuSubContent>
   171→        </DropdownMenuSub>
   172→      </DropdownMenuContent>
   173→    </DropdownMenu>
   174→  );
   175→}
